    private static class NativeBridgeMessage {
        String action;
        JSONObject payload;
        String callbackId;
        long timestamp;
    }

    private NativeBridgeMessage validateAndParseMessage(String messageJson) {
        if (messageJson == null || messageJson.isEmpty()) {
            Log.w(TAG, "Empty message received");
            return null;
        }

        // === SECURITY: Size limit to prevent DoS ===
        if (messageJson.length() > 10240) { // 10KB max
            Log.w(TAG, "Message too large: " + messageJson.length() + " bytes");
            return null;
        }

        try {
            JSONObject json = new JSONObject(messageJson);

            NativeBridgeMessage message = new NativeBridgeMessage();

            // Validate required fields
            if (!json.has("action") || !json.has("callbackId")) {
                Log.w(TAG, "Missing required fields in bridge message");
                return null;
            }

            message.action = json.getString("action");
            message.callbackId = json.getString("callbackId");
            message.payload = json.optJSONObject("payload");
            message.timestamp = json.optLong("timestamp", 0);

            // === SECURITY: Validate action is in whitelist ===
            if (!ALLOWED_ACTIONS.contains(message.action)) {
                Log.w(TAG, "Unauthorized action attempted: " + message.action);
                return null;
            }

            // === SECURITY: Validate callbackId format (UUID) ===
            if (!isValidCallbackId(message.callbackId)) {
                Log.w(TAG, "Invalid callbackId format");
                return null;
            }

            // === SECURITY: Validate timestamp (reject stale messages) ===
            if (message.timestamp > 0) {
                long now = System.currentTimeMillis();
                if (Math.abs(now - message.timestamp) > 60000) { // 60 second window
                    Log.w(TAG, "Stale message rejected");
                    return null;
                }
            }

            // Sanitize payload values
            if (message.payload != null) {
                message.payload = sanitizePayload(message.payload);
            }

            return message;

        } catch (JSONException e) {
            Log.w(TAG, "Invalid JSON in bridge message", e);
            return null;
        }
    }

    private boolean isValidCallbackId(String callbackId) {
        if (callbackId == null || callbackId.length() > 100) return false;
        // Allow UUID format or simple alphanumeric with hyphens/underscores
        return callbackId.matches("^[a-zA-Z0-9_-]{1,100}$");
    }

    private JSONObject sanitizePayload(JSONObject payload) {
        // Deep copy and sanitize string values
        JSONObject sanitized = new JSONObject();
        try {
            java.util.Iterator<String> keys = payload.keys();
            while (keys.hasNext()) {
                String key = keys.next();
                // Only allow alphanumeric keys
                if (!key.matches("^[a-zA-Z0-9_]{1,50}$")) continue;

                Object value = payload.get(key);
                if (value instanceof String) {
                    String strValue = (String) value;
                    // Limit string length and strip potential script injection
                    if (strValue.length() > 2048) {
                        strValue = strValue.substring(0, 2048);
                    }
                    // Remove potential script tags
                    strValue = strValue.replaceAll("<script[^>]*>.*?</script>", "");
                    sanitized.put(key, strValue);
                } else if (value instanceof Number || value instanceof Boolean) {
                    sanitized.put(key, value);
                } else if (value instanceof JSONObject) {
                    sanitized.put(key, sanitizePayload((JSONObject) value));
                }
                // Skip arrays and other types for safety
            }
        } catch (JSONException e) {
            Log.w(TAG, "Error sanitizing payload", e);
        }
        return sanitized;
    }

    private boolean isRateLimited(String action) {
        long now = System.currentTimeMillis();
        Long lastTimestamp = lastActionTimestamps.get(action);
        if (lastTimestamp != null && (now - lastTimestamp) < RATE_LIMIT_MS) {
            return true;
        }
        lastActionTimestamps.put(action, now);
        return false;
    }

    private void dispatchAction(NativeBridgeMessage message) {
        Log.d(TAG, "Dispatching action: " + message.action);

        switch (message.action) {
            case "getLocation":
                handleGetLocation(message.callbackId);
                break;
            case "openCamera":
                handleOpenCamera(message.callbackId);
                break;
            case "initiatePayment":
                handleInitiatePayment(message.callbackId, message.payload);
                break;
            case "getDeviceInfo":
                handleGetDeviceInfo(message.callbackId);
                break;
            case "hapticFeedback":
                handleHapticFeedback(message.callbackId);
                break;
            case "shareContent":
                handleShareContent(message.callbackId, message.payload);
                break;
            default:
                sendCallbackToWeb(message.callbackId,
                        createErrorResponse("Unknown action: " + message.action));
        }
    }

