    private void handleGetLocation(String callbackId) {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION)
                != PackageManager.PERMISSION_GRANTED) {
            // Store callback and request permission
            pendingCallbacks.put("location_" + callbackId, System.currentTimeMillis());
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.ACCESS_FINE_LOCATION},
                    PERMISSION_REQUEST_LOCATION);
            // Store callbackId for use after permission result
            pendingLocationCallbackId = callbackId;
            return;
        }

        fetchLocation(callbackId);
    }

    private String pendingLocationCallbackId;
    private String pendingCameraCallbackId;

    @SuppressLint("MissingPermission")
    private void fetchLocation(String callbackId) {
        CancellationTokenSource cts = new CancellationTokenSource();
        fusedLocationClient.getCurrentLocation(Priority.PRIORITY_HIGH_ACCURACY, cts.getToken())
                .addOnSuccessListener(this, location -> {
                    if (location != null) {
                        try {
                            JSONObject locationData = new JSONObject();
                            locationData.put("latitude", location.getLatitude());
                            locationData.put("longitude", location.getLongitude());
                            locationData.put("accuracy", location.getAccuracy());
                            locationData.put("timestamp", location.getTime());
                            sendCallbackToWeb(callbackId, createSuccessResponse(locationData));
                        } catch (JSONException e) {
                            sendCallbackToWeb(callbackId, createErrorResponse("Failed to serialize location"));
                        }
                    } else {
                        sendCallbackToWeb(callbackId, createErrorResponse("Location unavailable"));
                    }
                })
                .addOnFailureListener(this, e -> {
                    sendCallbackToWeb(callbackId, createErrorResponse("Location error: " + e.getMessage()));
                });
    }

    private void handleOpenCamera(String callbackId) {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                != PackageManager.PERMISSION_GRANTED) {
            pendingCameraCallbackId = callbackId;
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.CAMERA},
                    PERMISSION_REQUEST_CAMERA);
            return;
        }

        openCameraIntent(callbackId);
    }

    private void openCameraIntent(String callbackId) {
        pendingCameraCallbackId = callbackId;
        Intent cameraIntent = new Intent(android.provider.MediaStore.ACTION_IMAGE_CAPTURE);
        if (cameraIntent.resolveActivity(getPackageManager()) != null) {
            cameraLauncher.launch(cameraIntent);
        } else {
            sendCallbackToWeb(callbackId, createErrorResponse("Camera not available"));
        }
    }

    private void handleInitiatePayment(String callbackId, JSONObject payload) {
        if (payload == null) {
            sendCallbackToWeb(callbackId, createErrorResponse("Payment payload required"));
            return;
        }

        try {
            String amount = payload.optString("amount", "");
            String currency = payload.optString("currency", "USD");
            String description = payload.optString("description", "");

            // === SECURITY: Validate payment parameters ===
            if (amount.isEmpty() || !amount.matches("^\\d+(\\.\\d{1,2})?$")) {
                sendCallbackToWeb(callbackId, createErrorResponse("Invalid payment amount"));
                return;
            }

            double amountValue = Double.parseDouble(amount);
            if (amountValue <= 0 || amountValue > 99999.99) {
                sendCallbackToWeb(callbackId, createErrorResponse("Payment amount out of range"));
                return;
            }

            if (!currency.matches("^[A-Z]{3}$")) {
                sendCallbackToWeb(callbackId, createErrorResponse("Invalid currency code"));
                return;
            }

            // Show confirmation dialog to user
            runOnUiThread(() -> {
                new AlertDialog.Builder(this)
                        .setTitle("Confirm Payment")
                        .setMessage(String.format("Pay %s %s for %s?", currency, amount, description))
                        .setPositiveButton("Confirm", (dialog, which) -> {
                            // Process payment via your payment SDK
                            processPayment(callbackId, amountValue, currency, description);
                        })
                        .setNegativeButton("Cancel", (dialog, which) -> {
                            sendCallbackToWeb(callbackId, createErrorResponse("Payment cancelled by user"));
                        })
                        .setCancelable(false)
                        .show();
            });

        } catch (Exception e) {
            sendCallbackToWeb(callbackId, createErrorResponse("Payment processing error"));
        }
    }

    private void processPayment(String callbackId, double amount, String currency, String description) {
        // TODO: Integrate with your payment SDK (Stripe, Google Pay, etc.)
        // This is a placeholder for the actual payment processing
        try {
            JSONObject result = new JSONObject();
            result.put("transactionId", UUID.randomUUID().toString());
            result.put("status", "completed");
            result.put("amount", amount);
            result.put("currency", currency);
            sendCallbackToWeb(callbackId, createSuccessResponse(result));
        } catch (JSONException e) {
            sendCallbackToWeb(callbackId, createErrorResponse("Payment serialization error"));
        }
    }

    private void handleGetDeviceInfo(String callbackId) {
        try {
            JSONObject deviceInfo = new JSONObject();
            deviceInfo.put("platform", "android");
            deviceInfo.put("osVersion", android.os.Build.VERSION.RELEASE);
            deviceInfo.put("sdkVersion", android.os.Build.VERSION.SDK_INT);
            deviceInfo.put("model", android.os.Build.MODEL);
            deviceInfo.put("manufacturer", android.os.Build.MANUFACTURER);
            deviceInfo.put("appVersion", getPackageManager()
                    .getPackageInfo(getPackageName(), 0).versionName);
            deviceInfo.put("bridgeVersion", "1.0.0");
            sendCallbackToWeb(callbackId, createSuccessResponse(deviceInfo));
        } catch (Exception e) {
            sendCallbackToWeb(callbackId, createErrorResponse("Failed to get device info"));
        }
    }

    @SuppressLint("MissingPermission")
    private void handleHapticFeedback(String callbackId) {
        runOnUiThread(() -> {
            webView.performHapticFeedback(android.view.HapticFeedbackConstants.LONG_PRESS);
            sendCallbackToWeb(callbackId, createSuccessResponse("Haptic feedback triggered"));
        });
    }

    private void handleShareContent(String callbackId, JSONObject payload) {
        if (payload == null) {
            sendCallbackToWeb(callbackId, createErrorResponse("Share payload required"));
            return;
        }

        String title = payload.optString("title", "");
        String text = payload.optString("text", "");
        String url = payload.optString("url", "");

        // === SECURITY: Validate URL if provided ===
        if (!url.isEmpty() && !url.startsWith("https://")) {
            sendCallbackToWeb(callbackId, createErrorResponse("Only HTTPS URLs allowed for sharing"));
            return;
        }

        runOnUiThread(() -> {
            Intent shareIntent = new Intent(Intent.ACTION_SEND);
            shareIntent.setType("text/plain");
            if (!title.isEmpty()) shareIntent.putExtra(Intent.EXTRA_SUBJECT, title);

            StringBuilder shareText = new StringBuilder();
            if (!text.isEmpty()) shareText.append(text);
            if (!url.isEmpty()) {
                if (shareText.length() > 0) shareText.append("\n");
                shareText.append(url);
            }
            shareIntent.putExtra(Intent.EXTRA_TEXT, shareText.toString());

            try {
                startActivity(Intent.createChooser(shareIntent, "Share via"));
                sendCallbackToWeb(callbackId, createSuccessResponse("Share dialog opened"));
            } catch (Exception e) {
                sendCallbackToWeb(callbackId, createErrorResponse("Failed to open share dialog"));
            }
        });
    }

