    private boolean isAllowedOrigin(String url) {
        if (url == null) return false;
        try {
            Uri uri = Uri.parse(url);
            String origin = uri.getScheme() + "://" + uri.getHost();
            // Also check with port if present
            if (uri.getPort() != -1) {
                origin = uri.getScheme() + "://" + uri.getHost() + ":" + uri.getPort();
            }
            return ALLOWED_ORIGINS.contains(origin);
        } catch (Exception e) {
            return false;
        }
    }

    private void injectSecurityScript(WebView view) {
        // Inject a helper that wraps the bridge with promises and validation
        String script = "(function() {" +
                "  if (window.__nativeBridgeInitialized) return;" +
                "  window.__nativeBridgeInitialized = true;" +
                "" +
                "  window.HybridBridge = {" +
                "    _callbacks: {}," +
                "" +
                "    call: function(action, payload) {" +
                "      return new Promise(function(resolve, reject) {" +
                "        var callbackId = 'cb_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);" +
                "        window.HybridBridge._callbacks[callbackId] = { resolve: resolve, reject: reject };" +
                "" +
                "        var message = JSON.stringify({" +
                "          action: action," +
                "          payload: payload || {}," +
                "          callbackId: callbackId," +
                "          timestamp: Date.now()" +
                "        });" +
                "" +
                "        if (window.NativeBridge && window.NativeBridge.postMessage) {" +
                "          window.NativeBridge.postMessage(message);" +
                "        } else {" +
                "          reject(new Error('Native bridge not available'));" +
                "        }" +
                "" +
                "        setTimeout(function() {" +
                "          if (window.HybridBridge._callbacks[callbackId]) {" +
                "            delete window.HybridBridge._callbacks[callbackId];" +
                "            reject(new Error('Bridge call timed out'));" +
                "          }" +
                "        }, 30000);" +
                "      });" +
                "    }," +
                "" +
                "    _handleCallback: function(callbackId, response) {" +
                "      var cb = this._callbacks[callbackId];" +
                "      if (cb) {" +
                "        delete this._callbacks[callbackId];" +
                "        if (response && response.success) {" +
                "          cb.resolve(response.data);" +
                "        } else {" +
                "          cb.reject(new Error(response ? response.error : 'Unknown error'));" +
                "        }" +
                "      }" +
                "    }," +
                "" +
                "    getLocation: function() { return this.call('getLocation'); }," +
                "    openCamera: function() { return this.call('openCamera'); }," +
                "    initiatePayment: function(payload) { return this.call('initiatePayment', payload); }," +
                "    getDeviceInfo: function() { return this.call('getDeviceInfo'); }," +
                "    hapticFeedback: function() { return this.call('hapticFeedback'); }," +
                "    shareContent: function(payload) { return this.call('shareContent', payload); }" +
                "  };" +
                "" +
                "  // Dispatch custom event to notify web app that bridge is ready" +
                "  window.dispatchEvent(new CustomEvent('nativeBridgeReady'));" +
                "})();";

        view.evaluateJavascript(script, null);
    }

